/**
 * Canonical liturgical event definitions (General Roman Calendar + Franciscan extensions).
 * Schedules are expanded to concrete dates by generate-seed.mjs.
 *
 * Sources: General Roman Calendar (Roman Missal, English 2018); OFM/Franciscan family calendars.
 */

/** @typedef {'solemnity'|'feast'|'memorial'|'optional_memorial'|'commemoration'} LiturgicalRank */

/**
 * @typedef {{
 *   id: string,
 *   name: string,
 *   rank: LiturgicalRank,
 *   summary: string,
 *   description: string,
 *   liturgical_color: string | null,
 *   is_universal: boolean,
 *   is_franciscan_specific: boolean,
 *   role_titles: string,
 *   schedule:
 *     | { type: 'fixed'; month: number; day: number }
 *     | { type: 'easter_offset'; offset: number }
 *     | { type: 'baptism_lord' }
 *     | { type: 'christ_king' }
 *     | { type: 'holy_family' }
 * }} EventDef
 */

/** @type {(o: Partial<EventDef> & Pick<EventDef, 'id'|'name'|'rank'|'schedule'>) => EventDef} */
function ev(o) {
  return {
    summary: '',
    description: '',
    liturgical_color: null,
    is_universal: true,
    is_franciscan_specific: false,
    role_titles: '',
    ...o,
    description: o.description || o.summary || '',
  };
}

